// // When 'divs' is high and 'pcpi_rs2' is negative, this module assigns the positive of 'pcpi_rs2' shifted left by 31 bits to the 'divisor' output.
module top_module(
	input             clk, resetn,

	input [31:0]      pcpi_rs2,
        input             divs,
	output reg [62:0] divisor
);always @(posedge clk) begin
	   divisor <= (divs && pcpi_rs2[31] ? -pcpi_rs2 : pcpi_rs2) << 31;
	end

endmodule
